function Counter() {
  const [count, setCount] = useState(0);

  // Direct update
  const increment = () => setCount(count + 1);

  // Functional update (safe in batches)
  const incrementBy3 = () => {
    setCount(prev => prev + 1);
    setCount(prev => prev + 1);
    setCount(prev => prev + 1); // count increases by 3
  };

  // Object state
  const [user, setUser] = useState({ name: '', age: 0 });
  const updateName = (name) => setUser(prev => ({ ...prev, name }));

  // Lazy initialization
  const [data, setData] = useState(() => {
    const saved = localStorage.getItem('data');
    return saved ? JSON.parse(saved) : [];
  });

  return <div>...</div>;
}

function Toggle() {
  const [isOn, setIsOn] = useState(false);

  // Toggle: always use functional form
  const toggle = () => setIsOn(prev => !prev);

  // Reset
  const reset = () => setIsOn(false);

  // Set based on some condition
  const updateFromServer = (value) => setIsOn(value);

  return (
    <div>
      <button onClick={toggle}>{isOn ? 'ON' : 'OFF'}</button>
      <button onClick={reset}>Reset</button>
    </div>
  );
}
